    var ADDS = [{"p":"PART 6. 과세표준","q":[{"answer":"O","src":"2025 서울시 7급","text":"취득세 과세표준은 취득 당시의 가액으로 하지만, 연부로 취득한 경우에는 매회 사실상 지급되는 금액인 연부금액(취득금액에 포함되는 계약보증금 포함)이 과세표준의 기준이 된다.","exp":"연부취득은 전체 취득가액을 한 번에 잡지 않고 매회 사실상 지급하는 연부금액을 과세표준으로 하며, 취득금액에 포함되는 계약보증금도 여기에 들어간다. 취득시기도 각 회차의 사실상 연부금 지급일로 본다는 점과 짝을 이룬다."},{"answer":"X","text":"연부로 취득하는 경우 취득 당시의 가액은 매회 사실상 지급되는 연부금액으로 하되, 취득금액에 포함되는 계약보증금은 과세표준에서 제외한다.","exp":"계약보증금을 제외한다는 부분이 틀렸다. 연부금액에는 취득금액에 포함되는 계약보증금이 포함되어 과세표준을 구성한다. 매회 실제 지급하는 연부금(계약보증금 포함)이 그때그때 과세표준이 된다."}],"tb":[{"k":"sub","t":"연부취득의 과세표준"},{"k":"p","t":"연부(年賦)로 취득하는 경우에는 취득 당시의 가액을 매회 사실상 지급되는 금액인 연부금액으로 한다. 이때 취득금액에 포함되는 계약보증금도 연부금액에 포함되어 과세표준을 구성한다. 즉 전체 취득가액을 한 번에 과세표준으로 삼는 것이 아니라, 각 회차에 실제 지급하는 연부금을 그때그때 과세표준으로 보고, 취득시기도 각 회차의 사실상 연부금 지급일로 본다."}],"wi":["연부취득 과세표준 = 연부금액에서 계약보증금 제외 ❌ → 취득금액에 포함되는 계약보증금 포함 ⭕"]},{"p":"PART 8. 중과세율","q":[{"answer":"X","src":"2025 서울시 7급","text":"법인이 유상거래를 원인으로 주택을 취득하는 경우에는 일반적인 취득세율이 아니라 더 높은 중과기준세율을 적용하지만, 이렇게 중과되는 경우 해당 주택 범위에는 주택공유지분이나 부속토지만을 소유하는 것은 제외된다.","exp":"'중과기준세율'이 틀렸다. 법인의 주택 유상취득은 중과기준세율(2%)이 아니라 별도의 중과세율(12%)을 적용한다. 주택공유지분이나 부속토지만을 소유하는 것을 중과 주택 범위에서 제외한다는 부분은 옳다."},{"answer":"O","src":"2025 서울시 7급","text":"고급주택, 고급오락장, 고급선박, 골프장 중에서 어느 하나에 해당하는 부동산등을 취득하는 경우 취득세가 중과세되나, 다만 고급주택이나 고급오락장이더라도 일정 기간 내에 고급주택이나 고급오락장의 용도가 아닌 용도로 사용하기 위해 용도변경공사를 착공하는 경우는 취득세 중과세 대상에서 제외된다.","exp":"고급주택·고급오락장은 취득일부터 60일 이내에 그 용도가 아닌 용도로 사용하거나 용도변경공사를 착공하면 중과에서 제외된다. 같은 60일 제외가 골프장에는 없어 골프장은 무조건 중과된다는 점과 구별한다."}],"tb":[],"wi":["법인 유상 주택 취득 = 중과기준세율 2% ❌ → 별도 중과세율 12% ⭕ (주택공유지분·부속토지만 소유는 중과 주택에서 제외)"]},{"p":"PART 9. 취득시기","q":[{"answer":"O","src":"2025 서울시 7급","text":"판매하기 위하여 차량을 제조·조립·건조하는 경우 실수요자가 차량을 인도받은 날과 계약서 상의 잔금 지급일이 서로 다르면 두 날짜 중 더 빠른 날을 최초의 취득일로 본다.","exp":"주문·판매 목적으로 차량 등을 제조·조립·건조하는 경우의 취득시기는 실수요자가 인도받는 날과 계약상 잔금지급일 중 빠른 날이다. 사실상 잔금지급일 하나로 보는 일반 유상승계취득과 구별해야 한다."}],"tb":[],"wi":[]},{"p":"PART 10. 신고납부와 가산세","q":[{"answer":"X","src":"2025 서울시 7급","text":"지방자치단체의 투자기관(재투자기관 제외)이 취득세 과세물건을 연부로 매각하면 매각일부터 30일 이내에 그 물건 소재지를 관할하는 지방자치단체의 장에게 통보하거나 신고하여야 한다.","exp":"기한이 30일이 아니라 60일이라 틀렸다. 지자체 투자기관(재투자기관 제외)이 과세물건을 연부매각하면 매각일부터 60일 이내에 물건 소재지 관할 지자체장에게 통보하거나 신고하여야 한다."},{"answer":"O","text":"지방자치단체의 투자기관(재투자기관은 제외한다)이 취득세 과세물건을 연부로 매각하면 매각일부터 60일 이내에 그 물건 소재지를 관할하는 지방자치단체의 장에게 통보하거나 신고하여야 한다.","exp":"연부매각 통보 기한은 매각일부터 60일이다. 30일로 바꾸는 것이 함정이며, 재투자기관은 이 통보 의무 대상에서 제외된다는 점도 함께 기억한다."},{"answer":"O","src":"2025 서울시 7급","text":"부담부 증여, 무상취득, 상속, 실종 이외의 사유로 취득세 과세물건을 취득한 자는 그 취득한 날부터 60일 이내에 취득세를 신고하고 납부해야 하지만, 신고·납부기한 이내에 재산권의 취득·이전에 관한 사항을 공부에 등기나 등록하려는 경우라면 등기나 등록 신청서를 등기·등록관서에 접수하는 날까지 취득세를 신고·납부하여야 한다.","exp":"일반 취득은 취득일부터 60일 이내가 원칙이지만, 그 기한 안에 등기·등록하려면 등기·등록 신청서 접수일까지 앞당겨 신고·납부해야 한다. 등기를 먼저 하려면 세금부터 내라는 취지다."},{"answer":"X","text":"행정안전부장관 또는 지방자치단체의 장은 주택소유 관계 확인 및 취득세 납세의무자의 세대원 확인 등의 업무처리를 위하여 필요하더라도 법원행정처장에게 가족관계 등록사항에 대한 등록전산정보자료의 제공을 요청할 수 없다.","exp":"요청할 수 없다는 부분이 틀렸다. 행안부장관·지자체장은 주택소유 관계 및 세대원 확인 등을 위해 필요한 경우 전산매체를 이용하여 법원행정처장에게 가족관계 등록전산정보자료의 제공을 요청할 수 있다."},{"answer":"O","src":"2025 서울시 7급","text":"행정안전부장관 또는 지방자치단체의 장은 주택소유 관계 확인 및 취득세 납세의무자의 세대원 확인 등의 업무처리를 위하여 필요한 경우 전산매체를 이용하여 법원행정처장에게 「가족관계의 등록 등에 관한 법률」에 따라 가족관계 등록사항에 대한 등록전산정보자료의 제공을 요청할 수 있다.","exp":"주택 수·세대원 확인을 위해 행안부장관·지자체장은 법원행정처장에게 가족관계 등록전산정보자료 제공을 요청할 수 있다. 다주택 중과 판정 등에 필요한 과세자료 협력 규정이다."},{"answer":"X","text":"행정안전부장관이나 지방자치단체의 장은 「국세기본법」 또는 「상속세 및 증여세법」에 따른 부동산에 대한 증여세의 부과·징수 등에 관한 자료를 대통령령으로 정하는 바에 따라 세무서장이나 지방국세청장에게 통보하여야 한다.","exp":"통보 방향이 뒤바뀌어 틀렸다. 부동산 증여세의 부과·징수 자료는 세무서장·지방국세청장이 행정안전부장관·지방자치단체의 장에게 통보하여야 한다. 국세 당국에서 지방으로 넘기는 협력이다."},{"answer":"O","src":"2025 서울시 7급","text":"세무서장이나 지방국세청장은 「국세기본법」 또는 「상속세 및 증여세법」에 따른 부동산에 대한 증여세의 부과·징수 등에 관한 자료를 대통령령으로 정하는 바에 따라 행정안전부장관이나 지방자치단체의 장에게 통보하여야 한다.","exp":"국세 당국(세무서장·지방국세청장)이 부동산 증여세 부과·징수 자료를 행안부장관·지자체장에게 통보하여 취득세 과세에 활용하도록 하는 협력 규정이다. 통보 방향은 국세에서 지방으로다."}],"tb":[{"k":"sub","t":"등기·등록하려는 경우의 신고·납부 시점"},{"k":"p","t":"부담부증여·무상취득·상속·실종 외의 사유로 취득세 과세물건을 취득한 자는 취득한 날부터 60일 이내에 신고·납부한다. 다만 그 신고·납부기한 이내에 재산권의 취득·이전에 관한 사항을 공부에 등기·등록하려는 경우에는, 등기·등록 신청서를 등기·등록관서에 접수하는 날까지 취득세를 신고·납부하여야 한다. 등기를 먼저 하려면 그 접수 시점까지 세금을 내라는 취지다."},{"k":"sub","t":"연부매각 통보와 과세자료 통보 협력"},{"k":"p","t":"지방자치단체의 투자기관(재투자기관은 제외한다)이 취득세 과세물건을 연부로 매각하면, 매각일부터 60일 이내에 그 물건 소재지를 관할하는 지방자치단체의 장에게 통보하거나 신고하여야 한다. 기한을 30일로 바꾸는 함정에 주의한다."},{"k":"p","t":"행정안전부장관 또는 지방자치단체의 장은 주택소유 관계 확인 및 취득세 납세의무자의 세대원 확인 등을 위하여 필요한 경우 전산매체를 이용하여 법원행정처장에게 「가족관계의 등록 등에 관한 법률」에 따른 가족관계 등록전산정보자료의 제공을 요청할 수 있다. 다주택 중과 판정 등에 필요한 자료를 확보하기 위한 규정이다."},{"k":"p","t":"세무서장이나 지방국세청장은 「국세기본법」 또는 「상속세 및 증여세법」에 따른 부동산에 대한 증여세의 부과·징수 등에 관한 자료를 대통령령으로 정하는 바에 따라 행정안전부장관이나 지방자치단체의 장에게 통보하여야 한다. 국세 당국에서 지방자치단체로 자료가 넘어가 취득세 과세에 활용된다. 통보 방향(국세→지방)을 뒤집는 함정에 주의한다."}],"wi":["지자체 투자기관 연부매각 통보 = 매각일부터 30일 ❌ → 60일 이내 ⭕","증여세 부과·징수 자료 통보 = 행안부장관·지자체장 → 세무서장 ❌ → 세무서장·지방국세청장 → 행안부장관·지자체장 ⭕"]},{"p":"PART 12. 납세지","q":[{"answer":"X","src":"2025 서울시 7급","text":"차량에 대한 취득세 납세지는 소유자의 주소지로 한다.","exp":"소유자의 주소지가 틀렸다. 차량에 대한 취득세 납세지는 소유자의 주소지가 아니라 그 차량의 등록지다. 부동산이 소재지 기준인 것과 마찬가지로 차량은 등록지가 납세지다."},{"answer":"O","text":"차량에 대한 취득세 납세지는 그 차량의 등록지로 한다.","exp":"차량 납세지는 소유자 주소지가 아니라 등록지다. 기계장비도 등록지를 납세지로 하며, 소유자 주소지로 바꾸는 것이 대표 함정이다."},{"answer":"O","src":"2025 서울시 7급","text":"기계장비는 「건설기계관리법」에 따른 등록지를 납세지로 한다.","exp":"기계장비의 취득세 납세지는 건설기계관리법에 따른 등록지다. 차량과 함께 '등록지'가 납세지이며, 소유자의 주소지가 아니라는 점에 주의한다."},{"answer":"X","text":"입목에 대한 취득세 납세지는 입목 소유자의 주소지로 한다.","exp":"소유자의 주소지가 틀렸다. 입목에 대한 취득세 납세지는 그 입목이 서 있는 곳, 즉 입목 소재지다. 재산이 있는 곳에 낸다는 대원칙이 입목에도 적용된다."},{"answer":"O","src":"2025 서울시 7급","text":"입목은 입목 소재지를 납세지로 한다.","exp":"입목의 취득세 납세지는 입목 소재지다. 부동산 소재지와 같은 원리로 재산이 있는 곳이 납세지이며, 소유자 주소지가 아니다."}],"tb":[{"k":"p","t":"입목에 대한 취득세 납세지는 그 입목이 서 있는 토지가 있는 곳, 즉 입목 소재지로 한다. 차량·기계장비가 등록지, 부동산이 소재지인 것과 마찬가지로 '재산이 있는 곳에 낸다'는 대원칙이 입목에도 적용되며, 소유자의 주소지는 납세지가 아니다."}],"wi":["차량 납세지 = 소유자의 주소지 ❌ → 등록지 ⭕ (기계장비도 등록지)","입목 납세지 = 소유자 주소지 ❌ → 입목 소재지 ⭕"]}];
    for (var ai = 0; ai < ADDS.length; ai++) { insQ(ADDS[ai].p, ADDS[ai].q); insT(ADDS[ai].p, ADDS[ai].tb, ADDS[ai].wi); }
